class Solution:
    def findWinningPlayer(self, skills: List[int], k: int) -> int:
        max_skill = skills[0]
        current_streak = 0
        max_index = 0

        for i in range(1, len(skills)):
            if skills[i] > max_skill:
                max_skill = skills[i]
                max_index = i
                current_streak = 1
            else:
                current_streak += 1

            if current_streak == k:
                return max_index

        return max_index
